preflight.run:
$ErrorActionPreference = "Stop"
$PSNativeCommandUseErrorActionPreference = $true
$targetKey = "$env:SDKWORK_PACKAGE_PLATFORM/$env:SDKWORK_PACKAGE_ARCHITECTURE"
$rustTarget = switch ($targetKey) {
  "windows/x64" { "x86_64-pc-windows-msvc" }
  "windows/arm64" { "aarch64-pc-windows-msvc" }
  "linux/x64" { "x86_64-unknown-linux-gnu" }
  "linux/arm64" { "aarch64-unknown-linux-gnu" }
  "macos/x64" { "x86_64-apple-darwin" }
  "macos/arm64" { "aarch64-apple-darwin" }
  default { throw "Unsupported SDKWork Canvas desktop target $targetKey" }
}
rustup target add $rustTarget
if ($env:SDKWORK_PACKAGE_PLATFORM -eq "linux") {
  sudo apt-get update
  sudo apt-get install -y file libfuse2t64 libgbm-dev libgtk-3-dev libwebkit2gtk-4.1-dev libappindicator3-dev libpipewire-0.3-dev libssl-dev librsvg2-dev libwayland-dev libxkbcommon-dev pkg-config rpm patchelf
}

package.run:
$ErrorActionPreference = "Stop"
$PSNativeCommandUseErrorActionPreference = $true
$targetKey = "$env:SDKWORK_PACKAGE_PLATFORM/$env:SDKWORK_PACKAGE_ARCHITECTURE"
$rustTarget = switch ($targetKey) {
  "windows/x64" { "x86_64-pc-windows-msvc" }
  "windows/arm64" { "aarch64-pc-windows-msvc" }
  "linux/x64" { "x86_64-unknown-linux-gnu" }
  "linux/arm64" { "aarch64-unknown-linux-gnu" }
  "macos/x64" { "x86_64-apple-darwin" }
  "macos/arm64" { "aarch64-apple-darwin" }
  default { throw "Unsupported SDKWork Canvas desktop target $targetKey" }
}
pnpm release:desktop -- --target $rustTarget
if ($env:SDKWORK_PACKAGE_PLATFORM -eq "macos") {
  $bundleDir = "packages/sdkwork-canvas-pc-desktop/src-tauri/target/$rustTarget/release/bundle/macos"
  $appBundle = Get-ChildItem -Path $bundleDir -Directory -Filter "*.app" -ErrorAction SilentlyContinue | Select-Object -First 1
  if (-not $appBundle) {
    throw "Missing macOS .app bundle in $bundleDir"
  }
  Get-ChildItem -Path $bundleDir -File -Filter "*.app.tar.gz" -ErrorAction SilentlyContinue | Remove-Item -Force
  $archivePath = Join-Path $bundleDir "sdkwork-canvas-$env:SDKWORK_PACKAGE_VERSION-$env:SDKWORK_PACKAGE_ARCHITECTURE.app.tar.gz"
  tar -C $bundleDir -czf $archivePath $appBundle.Name
  if (-not (Test-Path -LiteralPath $archivePath -PathType Leaf)) {
    throw "Missing macOS app archive: $archivePath"
  }
}

validate.run:
$ErrorActionPreference = "Stop"
$targetKey = "$env:SDKWORK_PACKAGE_PLATFORM/$env:SDKWORK_PACKAGE_ARCHITECTURE"
$rustTarget = switch ($targetKey) {
  "windows/x64" { "x86_64-pc-windows-msvc" }
  "windows/arm64" { "aarch64-pc-windows-msvc" }
  "linux/x64" { "x86_64-unknown-linux-gnu" }
  "linux/arm64" { "aarch64-unknown-linux-gnu" }
  "macos/x64" { "x86_64-apple-darwin" }
  "macos/arm64" { "aarch64-apple-darwin" }
  default { throw "Unsupported SDKWork Canvas desktop target $targetKey" }
}
$bundleRoot = "packages/sdkwork-canvas-pc-desktop/src-tauri/target/$rustTarget/release/bundle"
$artifactGlob = switch ($env:SDKWORK_PACKAGE_FORMAT) {
  "msi" { Join-Path $bundleRoot "msi/*.msi" }
  "exe" { Join-Path $bundleRoot "nsis/*.exe" }
  "deb" { Join-Path $bundleRoot "deb/*.deb" }
  "rpm" { Join-Path $bundleRoot "rpm/*.rpm" }
  "appimage" { Join-Path $bundleRoot "appimage/*.AppImage" }
  "tar.gz" { Join-Path $bundleRoot "macos/*.app.tar.gz" }
  default { throw "Unsupported SDKWork Canvas package format $env:SDKWORK_PACKAGE_FORMAT" }
}
$artifacts = Get-ChildItem -Path $artifactGlob -File -ErrorAction SilentlyContinue
if (-not $artifacts) {
  throw "Missing built artifact for $env:SDKWORK_PACKAGE_ID matching $artifactGlob"
}
foreach ($artifact in $artifacts) {
  if ($artifact.Length -le 0) {
    throw "Built artifact is empty: $($artifact.FullName)"
  }
  Write-Host "Validated $($artifact.FullName)"
}
